 1	import React, { FC, useState } from 'react';
 2	
 3	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 4	import { Button, ExpandableSection, Stack, StackItem } from '@patternfly/react-core';
 5	
 6	const TemplateExpandableDescription: FC<{ description: string }> = ({ description }) => {
 7	  const { t } = useKubevirtTranslation();
 8	  const [isExpanded, setIsExpanded] = useState(description?.length <= 120);
 9	
10	  return (
11	    <Stack className="template-catalog-drawer-description">
12	      <StackItem>
13	        <ExpandableSection contentId="expandable-content" isDetached isExpanded>
14	          {isExpanded ? description : description.slice(0, 120).concat('...')}
15	        </ExpandableSection>
16	      </StackItem>
17	      {description.length > 120 && (
18	        <StackItem>
19	          <Button isInline onClick={() => setIsExpanded(!isExpanded)} variant="link">
20	            {isExpanded ? t('Collapse') : t('Read more')}
21	          </Button>
22	        </StackItem>
23	      )}
24	    </Stack>
25	  );
26	};
27	
28	export default TemplateExpandableDescription;

